// Shared coordinate validation + error wrapper for weather endpoints.
// Parses lat/lon from query params, validates ranges, calls fn(lat, lon),
// and catches unexpected errors with a caller-specific label.
//
// NOTE: The try/catch here is a safety net for truly unexpected runtime errors
// (null access, type errors, etc.) ŌĆö NOT for expected failures from functions
// like fetchWeather or analyzeDirections, which use the Result pattern
// ({ ok, data/error }) and are checked explicitly in the handler callback.
async function withValidatedCoords(c: any, fn: (lat: number, lon: number) => Promise<any>, errorLabel: string) {
  const lat = parseFloat(c.req.query('lat'));
  const lon = parseFloat(c.req.query('lon'));

  // Reject missing or non-numeric coordinates
  if (isNaN(lat) || isNaN(lon)) {
    return c.json({ error: true, message: 'lat and lon query parameters are required' }, 400);
  }

  // Reject out-of-range values
  if (lat < -90 || lat > 90 || lon < -180 || lon > 180) {
    return c.json({ error: true, message: 'Invalid coordinates: lat must be -90..90, lon must be -180..180' }, 400);
  }

  // Delegate to the caller's logic; wrap truly unexpected failures in a 500
  try {
    return await fn(lat, lon);
  } catch (err) {
    log.error(errorLabel + ': ' + err.message);
    return c.json({ error: true, message: errorLabel }, 500);
  }
}
